    pub left_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    pub key: String,
    pub data: Option<String>,
    pub weak_ref_count: u8,
    pub weak_ref_node_valid: u8,
}

pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

fn imax(i1: u32, i2: u32) -> u32 {
    if i1 > i2 { i1 } else { i2 }
}

fn get_node_depth(node: &Option<Rc<RefCell<BOSNode>>>) -> i32 {
    node.as_ref().map_or(0, |n| n.borrow().depth as i32 + 1)
}


fn bostree_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let n = node.borrow();
    let left_depth = get_node_depth(&n.left_child_node);
    let right_depth = get_node_depth(&n.right_child_node);
    right_depth - left_depth
}

fn upgrade_parent(parent: &Option<Weak<RefCell<BOSNode>>>) -> Option<Rc<RefCell<BOSNode>>> {
    parent.as_ref().and_then(|w| w.upgrade())
}

fn _bostree_rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = p.borrow().left_child_node.clone().unwrap();
    let l_right = l.borrow().right_child_node.clone();
    let p_parent_opt = upgrade_parent(&p.borrow().parent_node);
    let p_is_left = p_parent_opt.as_ref().map_or(false, |parent| {
        parent.borrow().left_child_node.as_ref().map_or(false, |left| Rc::ptr_eq(left, p))
    });

    if let Some(ref parent) = p_parent_opt {
        if p_is_left {
            parent.borrow_mut().left_child_node = Some(l.clone());
        } else {
            parent.borrow_mut().right_child_node = Some(l.clone());
        }
    } else {
        tree.root_node = Some(l.clone());
    }

    l.borrow_mut().parent_node = p.borrow().parent_node.clone();


    let right_count = l.borrow().right_child_count;
    p.borrow_mut().left_child_node = l_right.clone();
    p.borrow_mut().left_child_count = right_count;
    if let Some(ref right_child) = l_right {
        right_child.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }


    {
        let left_child_depth = p.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let right_child_depth = p.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        p.borrow_mut().depth = imax(left_child_depth, right_child_depth);
        p.borrow_mut().parent_node = Some(Rc::downgrade(&l));
    }

    let p_left_count = p.borrow().left_child_count;
    let p_right_count = p.borrow().right_child_count;
    l.borrow_mut().right_child_node = Some(p.clone());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));
    l.borrow_mut().right_child_count = p_left_count + p_right_count + 1;

    {
        let left_child_depth = l.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let right_child_depth = l.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        l.borrow_mut().depth = imax(left_child_depth, right_child_depth);
    }

    l
}

fn _bostree_rotate_left(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let r = p.borrow().right_child_node.clone().unwrap();
    let r_left = r.borrow().left_child_node.clone();
    let p_parent_opt = upgrade_parent(&p.borrow().parent_node);
    let p_is_left = p_parent_opt.as_ref().map_or(false, |parent| {
        parent.borrow().left_child_node.as_ref().map_or(false, |left| Rc::ptr_eq(left, p))
    });

    if let Some(ref parent) = p_parent_opt {
        if p_is_left {
            parent.borrow_mut().left_child_node = Some(r.clone());
        } else {
            parent.borrow_mut().right_child_node = Some(r.clone());
        }
    } else {
        tree.root_node = Some(r.clone());
    }

    r.borrow_mut().parent_node = p.borrow().parent_node.clone();


    let left_count = r.borrow().left_child_count;
    p.borrow_mut().right_child_node = r_left.clone();
    p.borrow_mut().right_child_count = left_count;
    if let Some(ref left_child) = r_left {
        left_child.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    {
        let left_child_depth = p.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let right_child_depth = p.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        p.borrow_mut().depth = imax(left_child_depth, right_child_depth);
        p.borrow_mut().parent_node = Some(Rc::downgrade(&r));
    }

    let p_left_count = p.borrow().left_child_count;
    let p_right_count = p.borrow().right_child_count;
    r.borrow_mut().left_child_node = Some(p.clone());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&r));
    r.borrow_mut().left_child_count = p_left_count + p_right_count + 1;

    {
        let left_child_depth = r.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let right_child_depth = r.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        r.borrow_mut().depth = imax(left_child_depth, right_child_depth);
    }

    r
}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        if let Some(ref root) = self.root_node {
            let r = root.borrow();
            r.left_child_count + r.right_child_count + 1
        } else {
            0
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut current = self.root_node.clone();
        let mut parent: Option<Rc<RefCell<BOSNode>>> = None;

        while let Some(ref curr) = current {
            parent = Some(curr.clone());
            let cmp = (self.cmp_function)(&key, &curr.borrow().key);
            if cmp < 0 {
                curr.borrow_mut().left_child_count += 1;
                current = curr.borrow().left_child_node.clone();
            } else {
                curr.borrow_mut().right_child_count += 1;
                current = curr.borrow().right_child_node.clone();
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));


        if let Some(ref p) = parent {
            let cmp = (self.cmp_function)(&new_node.borrow().key, &p.borrow().key);
            if cmp < 0 {
                p.borrow_mut().left_child_node = Some(new_node.clone());
            } else {
                p.borrow_mut().right_child_node = Some(new_node.clone());
            }
        } else {
            self.root_node = Some(new_node.clone());
            return new_node;
        }


        if let Some(ref parent_node) = parent {
            let left_exists = parent_node.borrow().left_child_node.is_some();
            let right_exists = parent_node.borrow().right_child_node.is_some();
            if left_exists ^ right_exists {
                parent_node.borrow_mut().depth += 1;
                let mut current_parent = upgrade_parent(&parent_node.borrow().parent_node);
                while let Some(ref pp) = current_parent {
                    let left_depth = pp.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    let right_depth = pp.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    let max_depth = imax(left_depth, right_depth);


                    if pp.borrow().depth != max_depth {
                        pp.borrow_mut().depth = max_depth;
                    } else {
                        break;
                    }

                    let left_depth_i = left_depth as i32;
                    let right_depth_i = right_depth as i32;
                    if left_depth_i - 2 == right_depth_i {
                        if bostree_balance(&pp.borrow().left_child_node.as_ref().unwrap()) > 0 {
                            _bostree_rotate_left(self, &pp.borrow().left_child_node.as_ref().unwrap());
                        }
                        _bostree_rotate_right(self, pp);
                        break;
                    } else if left_depth_i + 2 == right_depth_i {
                        if bostree_balance(&pp.borrow().right_child_node.as_ref().unwrap()) < 0 {
                            _bostree_rotate_right(self, &pp.borrow().right_child_node.as_ref().unwrap());
                        }
                        _bostree_rotate_left(self, pp);
                        break;
                    }
                    current_parent = upgrade_parent(&pp.borrow().parent_node);
                }
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let has_left = node.borrow().left_child_node.is_some();
        let has_right = node.borrow().right_child_node.is_some();
        let mut bubble_up: Option<Rc<RefCell<BOSNode>>> = None;

        if has_left && has_right {
            node.borrow_mut().left_child_count -= 1;
            let mut candidate = node.borrow().left_child_node.clone().unwrap();
            while candidate.borrow().right_child_node.is_some() {
                candidate.borrow_mut().right_child_count -= 1;
                candidate = candidate.borrow().right_child_node.clone().unwrap();
            }
            let lost_child = candidate.borrow().left_child_node.clone();

            let bubble_start = candidate.borrow().parent_node.as_ref().unwrap().upgrade().unwrap();
            let bubble_is_left = bubble_start.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
            {
                let mut bs_mut = bubble_start.borrow_mut();
                if bubble_is_left {
                    bs_mut.left_child_node = lost_child.clone();
                } else {
                    bs_mut.right_child_node = lost_child.clone();
                }
            }
            if let Some(ref child) = lost_child {
                child.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            let node_parent = upgrade_parent(&node.borrow().parent_node);

            if let Some(np) = node_parent {
                let is_left = np.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                let mut np_mut = np.borrow_mut();
                if is_left {
                    np_mut.left_child_node = Some(candidate.clone());
                } else {
                    np_mut.right_child_node = Some(candidate.clone());
                }
            } else {
                self.root_node = Some(candidate.clone());
            }

            candidate.borrow_mut().parent_node = node.borrow().parent_node.clone();
            let cand_left = node.borrow().left_child_node.clone();
            let cand_right = node.borrow().right_child_node.clone();
            let left_count = node.borrow().left_child_count;
            let right_count = node.borrow().right_child_count;

            candidate.borrow_mut().left_child_node = cand_left.clone();
            candidate.borrow_mut().left_child_count = left_count;
            candidate.borrow_mut().right_child_node = cand_right.clone();
            candidate.borrow_mut().right_child_count = right_count;
            if let Some(ref left_child) = cand_left {
                left_child.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(ref right_child) = cand_right {
                right_child.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            let mut bs = bubble_start.clone();
            while !Rc::ptr_eq(&bs, &candidate) {
                {
                    let left_depth = bs.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    let right_depth = bs.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    bs.borrow_mut().depth = imax(left_depth, right_depth);
                }

                let balance = bostree_balance(&bs);
                if balance > 1 {
                    let right_child = bs.borrow().right_child_node.as_ref().unwrap().clone();
                    if bostree_balance(&right_child) < 0 {
                        _bostree_rotate_right(self, &right_child);
                    }
                    bs = _bostree_rotate_left(self, &bs);
                } else if balance < -1 {
                    let left_child = bs.borrow().left_child_node.as_ref().unwrap().clone();
                    if bostree_balance(&left_child) > 0 {
                        _bostree_rotate_left(self, &left_child);
                    }
                    bs = _bostree_rotate_right(self, &bs);
                }

                if let Some(np) = upgrade_parent(&bs.borrow().parent_node) {
                    bs = np;
                } else {
                    break;
                }
            }

            {
                let left_depth = candidate.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let right_depth = candidate.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                candidate.borrow_mut().depth = imax(left_depth, right_depth);
            }

            bubble_up = upgrade_parent(&candidate.borrow().parent_node);

            if let Some(ref bu) = bubble_up {
                let is_left = bu.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
                {
                    let mut bu_mut = bu.borrow_mut();
                    if is_left {
                        bu_mut.left_child_count -= 1;
                    } else {
                        bu_mut.right_child_count -= 1;
                    }
                }
            }
        } else {
            let node_parent = upgrade_parent(&node.borrow().parent_node);

            if node_parent.is_none() {
                if let Some(ref left_child) = node.borrow().left_child_node {
                    self.root_node = Some(left_child.clone());
                    left_child.borrow_mut().parent_node = None;
                } else if let Some(ref right_child) = node.borrow().right_child_node {
                    self.root_node = Some(right_child.clone());
                    right_child.borrow_mut().parent_node = None;
                } else {
                    self.root_node = None;
                }
            } else {
                let candidate = if node.borrow().left_child_node.is_some() {
                    node.borrow().left_child_node.clone()
                } else {
                    node.borrow().right_child_node.clone()
                };

                let candidate_count = if node.borrow().left_child_node.is_some() {
                    node.borrow().left_child_count
                } else {
                    node.borrow().right_child_count
                };

                if let Some(ref np) = node_parent {
                    let is_left = np.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                    {
                        let mut np_mut = np.borrow_mut();
                        if is_left {
                            np_mut.left_child_node = candidate.clone();
                            np_mut.left_child_count = candidate_count;
                        } else {
                            np_mut.right_child_node = candidate.clone();
                            np_mut.right_child_count = candidate_count;
                        }
                    }

                    if let Some(ref c) = candidate {
                        c.borrow_mut().parent_node = Some(Rc::downgrade(np));
                    }
                }

                bubble_up = node_parent;
            }
        }

        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);

        let mut bubbling_finished = false;
        while let Some(bu) = bubble_up {
            if !bubbling_finished {
                {
                    let left_depth = bu.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    let right_depth = bu.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    let new_depth = imax(left_depth, right_depth);
                    if new_depth != bu.borrow().depth {
                        bu.borrow_mut().depth = new_depth;
                    } else {
                        bubbling_finished = true;
                    }
                }

                let balance = bostree_balance(&bu);
                if balance < -1 {
                    let left_child = bu.borrow().left_child_node.as_ref().unwrap().clone();
                    if bostree_balance(&left_child) > 0 {
                        _bostree_rotate_left(self, &left_child);
                    }
                    bubble_up = Some(_bostree_rotate_right(self, &bu));
                    bubbling_finished = false;
                } else if balance > 1 {
                    let right_child = bu.borrow().right_child_node.as_ref().unwrap().clone();
                    if bostree_balance(&right_child) < 0 {
                        _bostree_rotate_right(self, &right_child);
                    }
                    bubble_up = Some(_bostree_rotate_left(self, &bu));
                    bubbling_finished = false;
                }
            }


            if !bubbling_finished {
                bubble_up = upgrade_parent(&bu.borrow().parent_node);
            }
        }
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count = node.borrow().weak_ref_count.saturating_sub(1);

        if node.borrow().weak_ref_count == 0 {
            if let Some(ref free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();

        while let Some(current) = node {
            let cmp = (self.cmp_function)(key, &current.borrow().key);
            if cmp == 0 {
                return Some(current);
            } else if cmp < 0 {
                node = current.borrow().left_child_node.clone();
            } else {
                node = current.borrow().right_child_node.clone();
            }
        }

        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        let mut idx = index;

        while let Some(current) = node {
            let left_count = current.borrow().left_child_count;

            if left_count <= idx {
                idx -= left_count;
                if idx == 0 {
                    return Some(current);
                }
                idx -= 1;
                node = current.borrow().right_child_node.clone();
            } else {
                node = current.borrow().left_child_node.clone();
            }
        }

        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if let Some(ref root) = self.root_node {
            println!("digraph {");
            println!("  ordering = out;");
            _bostree_print_helper(root);
            println!("}}");
        }
    }
}

#[cfg(debug_assertions)]
fn _bostree_print_helper(node: &Rc<RefCell<BOSNode>>) {
    let n = node.borrow();
    println!(
        "  {} [label=\"\\N ({},{},{})\"];",
        n.key,
        n.left_child_count,
        n.right_child_count,
        n.depth
    );

    if let Some(ref parent) = n.parent_node {
        if let Some(p) = parent.upgrade() {
            println!("  {} -> {} [color=green];", n.key, p.borrow().key);
        }
    }

    if let Some(ref left) = n.left_child_node {
        println!("  {} -> {}", n.key, left.borrow().key);
        _bostree_print_helper(left);
    }

    if let Some(ref right) = n.right_child_node {
        println!("  {} -> {}", n.key, right.borrow().key);
        _bostree_print_helper(right);
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if node.borrow().right_child_node.is_some() {
        let mut current = node.borrow().right_child_node.clone().unwrap();
        loop {
            match current.borrow().left_child_node.clone() {
                Some(left) => current = left,
                None => return Some(current),
            }
        }
    }

    let mut current = node.clone();
    loop {
        let parent_opt = {
            let current_ref = current.borrow();
            if current_ref.parent_node.is_none() {
                None
            } else {
                current_ref.parent_node.as_ref().unwrap().upgrade()
            }
        };

        let Some(parent) = parent_opt else {
            break;
        };


        if parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
            current = parent;
        } else {
            return Some(parent);
        }
    }

    None
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if node.borrow().left_child_node.is_some() {
        let mut current = node.borrow().left_child_node.clone().unwrap();
        loop {
            match current.borrow().right_child_node.clone() {
                Some(right) => current = right,
                None => return Some(current),
            }
        }
    }

    let mut current = node.clone();
    loop {
        let parent_opt = {
            let current_ref = current.borrow();
            if current_ref.parent_node.is_none() {
                None
            } else {
                current_ref.parent_node.as_ref().unwrap().upgrade()
            }
        };

        let Some(parent) = parent_opt else {
            break;
        };


        if parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
            current = parent;
        } else {
            return Some(parent);
        }
    }

    None
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();

    loop {
        let (parent_opt, left_count, is_right) = {
            let current_ref = current.borrow();
            if current_ref.parent_node.is_none() {
                (None, 0, false)
            } else {
                let parent = current_ref.parent_node.as_ref().unwrap().upgrade().unwrap();
                let left_count = parent.borrow().left_child_count;
                let is_right = parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current));
                (Some(parent), left_count, is_right)
            }
        };

        let Some(parent) = parent_opt else {
            break;
        };


        if is_right {
            counter += 1 + left_count;
        }
        current = parent;
    }

    counter
}
