    let mut current = node.clone();
    loop {
        let parent_opt = {
            let current_ref = current.borrow();
            if current_ref.parent_node.is_none() {
                None
            } else {
                current_ref.parent_node.as_ref().unwrap().upgrade()
            }
        };

        let Some(parent) = parent_opt else {
