pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let mut current = node.borrow().right_child_node.clone();
    while let Some(curr) = current {
        let next = {
            let c = curr.borrow();
            c.left_child_node.clone()
        };
        if next.is_none() {
            return Some(curr);
        }
        current = next;
    }

    let mut current = node.clone();
    loop {
        let parent_opt = {
            let current_ = current.borrow();
            if current_ .parent_node.is_none() {
                None
            } else {
                current_ .parent_node.as_ref().unwrap().upgrade()
            }
        };

        let Some(parent) = parent_opt else {
