pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();

    loop {
        let (parent_opt, left_dex_ , is_right) = {
            let current_ = current.borrow();
            if current_ .parent_node.is_none() {
                (None, 0, false)
            } else {
                let parent = current_ .parent_node.as_ref().unwrap().upgrade().unwrap();
                let left_dex_ = parent.borrow().left_child_count;
                let is_right = parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current));
                (Some(parent), left_dex_ , is_right)
            }
        };

        let Some(parent) = parent_opt else {
            break;
        };

        if is_right {
            counter += 1 + left_dex_ ;
        }
        current = parent;
    }

    counter
}
