fn _bostree_rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = p.borrow().left_child_node.clone().unwrap();
    let l_right = l.borrow().right_child_node.clone();
    let p_parent_opt = upgrade_parent(&p.borrow().parent_node);
    let p_is_left = p_parent_opt.as_ref().map_or(false, |parent| {
        parent.borrow().left_child_node.as_ref().map_or(false, |left| Rc::ptr_eq(left, p))
    });
    if let Some(ref parent) = p_parent_opt {
        if p_is_left { parent.borrow_mut().left_child_node = Some(l.clone()); }
        else { parent.borrow_mut().right_child_node = Some(l.clone()); }
    } else { tree.root_node = Some(l.clone()); }
    l.borrow_mut().parent_node = p.borrow().parent_node.clone();
