            let bubble_is_left = bubble_start.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
            { let mut bs_mut = bubble_start.borrow_mut(); if bubble_is_left { bs_mut.left_child_node = lost_child.clone(); } else { bs_mut.right_child_node = lost_child.clone(); } }
