            candidate.borrow_mut().parent_node = node.borrow().parent_node.clone();
            let cand_left = node.borrow().left_child_node.clone(); let cand_right = node.borrow().right_child_node.clone();
            let left_count = node.borrow().left_child_count; let right_count = node.borrow().right_child_count;
            candidate.borrow_mut().left_child_node = cand_left.clone(); candidate.borrow_mut().left_child_count = left_count;
            candidate.borrow_mut().right_child_node = cand_right.clone(); candidate.borrow_mut().right_child_count = right_count;
            if let Some(ref left_child) = cand_left { left_child.borrow_mut().parent_node = Some(Rc::downgrade(&candidate)); }
            if let Some(ref right_child) = cand_right { right_child.borrow_mut().parent_node = Some(Rc::downgrade(&candidate)); }
            let mut bs = bubble_start.clone();
            loop { if Rc::ptr_eq(&bs, &candidate) { break; } { let left_depth = bs.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1); let right_depth = bs.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1); bs.borrow_mut().depth = imax(left_depth, right_depth); } let balance = bostree_balance(&bs); if balance > 1 { let right_child = bs.borrow().right_child_node.as_ref().unwrap().clone(); if bostree_balance(&right_child) < 0 { _bostree_rotate_right(self, &right_child); } bs = _bostree_rotate_left(self, &bs); } else if balance < -1 { let left_child = bs.borrow().left_child_node.as_ref().unwrap().clone(); if bostree_balance(&left_child) > 0 { _bostree_rotate_left(self, &left_child); } bs = _bostree_rotate_right(self, &bs); } else { let parent_opt = upgrade_parent(&bs.borrow().parent_node); match parent_opt { Some(np) => bs = np, None => break } } }
            { let left_depth = candidate.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1); let right_depth = candidate.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1); candidate.borrow_mut().depth = imax(left_depth, right_depth); }
