                let candidate = if node.borrow().left_child_node.is_some() { node.borrow().left_child_node.clone() } else { node.borrow().right_child_node.clone() };
                let candidate_count = if node.borrow().left_child_node.is_some() { node.borrow().left_child_count } else { node.borrow().right_child_count };
                if let Some(ref np) = node_parent { let is_left = np.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node)); let mut np_mut = np.borrow_mut(); if is_left { np_mut.left_child_node = candidate.clone(); np_mut.left_child_count = candidate_count; } else { np_mut.right_child_node = candidate.clone(); np_mut.right_child_count = candidate_count; } if let Some(ref c) = candidate { c.borrow_mut().parent_node = Some(Rc::downgrade(np)); } }
