    pub fn bostree_node_weak_unref(&mut self, node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count = node.borrow().weak_ref_count.saturating_sub(1);
        if node.borrow().weak_ref_count == 0 { if let Some(ref free_fn) = self.free_function { free_fn(node); } None } else if node.borrow().weak_ref_node_valid != 0 { Some(node.clone()) } else { None }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(current) = node { let cmp = (self.cmp_function)(key, &current.borrow().key); if cmp == 0 { return Some(current); } else if cmp < 0 { node = current.borrow().left_child_node.clone(); } else { node = current.borrow().right_child_node.clone(); } } None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone(); let mut idx = index;
        while let Some(current) = node { let left_count = current.borrow().left_child_count; if left_count <= idx { idx -= left_count; if idx == 0 { return Some(current); } idx -= 1; node = current.borrow().right_child_node.clone(); } else { node = current.borrow().left_child_node.clone(); } } None
    }

    #[cfg(debug_assertions)] pub fn bostree_print(&self) {
        if let Some(ref root) = self.root_node { println!("digraph {"); println!("  ordering = out;"); _bostree_print_helper(root); println!("}}"); }
