}

#[cfg(debug_assertions)] fn _bostree_print_helper(node: &Rc<RefCell<BOSNode>>) {
    let n = node.borrow();
    println!("  {} [label=\"\\N ({},{},{})\"];", n.key, n.left_child_count, n.right_child_count, n.depth);
    if let Some(ref parent) = n.parent_node { if let Some(p) = parent.upgrade() { println!("  {} -> {} [color=green];", n.key, p.borrow().key); } }
    if let Some(ref left) = n.left_child_node { println!("  {} -> {}", n.key, left.borrow().key); _bostree_print_helper(left); }
    if let Some(ref right) = n.right_child_node { println!("  {} -> {}", n.key, right.borrow().key); _bostree_print_helper(right); }
}

