pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let mut current = node.borrow().right_child_node.clone();
    while let Some(curr) = current { let next = { let c = curr.borrow(); c.left_child_node.clone() }; if next.is_none() { return Some(curr); } current = next; }
    let mut current = node.clone();
    loop { let parent_opt = { let cur = current.borrow(); if cur.parent_node.is_none() { None } else { cur.parent_node.as_ref().unwrap().upgrade() } }; let Some(parent) = parent_opt else { break; }; if parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) { current = parent; } else { return Some(parent); } } None
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let mut current = node.borrow().left_child_node.clone();
    while let Some(curr) = current { let next = { let c = curr.borrow(); c.right_child_node.clone() }; if next.is_none() { return Some(curr); } current = next; }
    let mut current = node.clone();
    loop { let parent_opt = { let cur = current.borrow(); if cur.parent_node.is_none() { None } else { cur.parent_node.as_ref().unwrap().upgrade() } }; let Some(parent) = parent_opt else { break; }; if parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) { current = parent; } else { return Some(parent); } } None
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();
    loop { let (parent_opt, left_count, is_right) = { let cur = current.borrow(); if cur.parent_node.is_none() { (None, 0, false) } else { let parent = cur.parent_node.as_ref().unwrap().upgrade().unwrap(); let left_count = parent.borrow().left_child_count; let is_right = parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)); (Some(parent), left_count, is_right) } }; let Some(parent) = parent_opt else { break; }; if is_right { counter += 1 + left_count; } current = parent; } counter
}
